+
+      function showOverlay(title, text, buttonLabel) {
+        overlayTitle.textContent = title;
+        overlayText.textContent = text;
+        restartBtn.textContent = buttonLabel;
+        overlay.classList.add('show');
+      }
+
+      function hideOverlay() {
+        overlay.classList.remove('show');
+      }
+
+      function spawnFood() {
+        do {
+          food = {
+            x: Math.floor(Math.random() * GRID),
+            y: Math.floor(Math.random() * GRID)
+          };
+        } while (snake.some(segment => segment.x === food.x && segment.y === food.y));
+      }
+
+      function startGame() {
+        if (gameOver) resetGame();
+        running = true;
+        hideOverlay();
+      }
+
+      function endGame() {
+        running = false;
+        gameOver = true;
+        if (score > best) {
+          best = score;
+          localStorage.setItem('snake-best', String(best));
+          bestEl.textContent = best;
+        }
+        showOverlay('Game Over', `Final score: ${score}. Press restart or hit R to try again.`, 'Restart');
+      }
+
+      function restartGame() {
+        resetGame();
+        startGame();
+      }
+
+      function sameDir(a, b) {
+        return a.x === b.x && a.y === b.y;
+      }
+
+      function setDirection(x, y) {
+        const proposed = { x, y };
+        if (sameDir(proposed, { x: -dir.x, y: -dir.y })) return;
+        nextDir = proposed;
+        if (!running && !gameOver) startGame();
+      }
+
+      function update(timestamp) {
+        requestAnimationFrame(update);
+        if (!running) {
+          draw();
+          return;
+        }
+        if (timestamp - lastMove < SPEED) return;
+        lastMove = timestamp;
+
+        dir = nextDir;
+        const head = { x: snake[0].x + dir.x, y: snake[0].y + dir.y };
+
+        if (head.x < 0 || head.x >= GRID || head.y < 0 || head.y >= GRID) {
+          endGame();
+          draw();
+          return;
+        }
+
+        if (snake.some(segment => segment.x === head.x && segment.y === head.y)) {
+          endGame();
+          draw();
+          return;
+        }
+
+        snake.unshift(head);
+
+        if (head.x === food.x && head.y === food.y) {
+          score += 10;
+          scoreEl.textContent = score;
+          spawnFood();
+        } else {
+          snake.pop();
+        }
+
+        draw();
+      }
+
+      function drawGrid() {
+        ctx.save();
+        ctx.globalAlpha = 0.24;
+        ctx.strokeStyle = '#6f86c9';
+        ctx.lineWidth = 1;
+        for (let i = 0; i < GRID; i++) {
+          ctx.beginPath();
+          ctx.moveTo(i * CELL + 0.5, 0);
+          ctx.lineTo(i * CELL + 0.5, canvas.height);
+          ctx.stroke();
+          ctx.beginPath();
+          ctx.moveTo(0, i * CELL + 0.5);
+          ctx.lineTo(canvas.width, i * CELL + 0.5);
+          ctx.stroke();
+        }
+        ctx.restore();
+      }
+
+      function drawCell(x, y, color, glow = false) {
+        const pad = 3;
+        const size = CELL - pad * 2;
+        const px = x * CELL + pad;
+        const py = y * CELL + pad;
+        const radius = 8;
+
+        ctx.save();
+        if (glow) {
+          ctx.shadowColor = color;
+          ctx.shadowBlur = 18;
+        }
+        const grad = ctx.createLinearGradient(px, py, px + size, py + size);
+        grad.addColorStop(0, color);
+        grad.addColorStop(1, '#ffffff');
+        ctx.fillStyle = grad;
+        roundRect(ctx, px, py, size, size, radius);
+        ctx.fill();
+        ctx.restore();
+      }
+
+      function roundRect(context, x, y, width, height, radius) {
+        const r = Math.min(radius, width / 2, height / 2);
+        context.beginPath();
+        context.moveTo(x + r, y);
+        context.arcTo(x + width, y, x + width, y + height, r);
+        context.arcTo(x + width, y + height, x, y + height, r);
+        context.arcTo(x, y + height, x, y, r);
+        context.arcTo(x, y, x + width, y, r);
+        context.closePath();
+      }
+
+      function draw() {
+        ctx.clearRect(0, 0, canvas.width, canvas.height);
+        drawGrid();
+
+        // Food pulse.
+        const pulse = 0.85 + Math.sin(performance.now() / 160) * 0.08;
+        ctx.save();
+        ctx.globalAlpha = pulse;
+        drawCell(food.x, food.y, '#ffcf5a', true);
+        ctx.restore();
+
+        snake.forEach((segment, index) => {
+          const color = index === 0 ? '#f4fff7' : '#8ef5a8';
+          const glow = index === 0;
+          drawCell(segment.x, segment.y, color, glow);
+        });
+
+        if (!running && !gameOver) {
+          ctx.save();
+          ctx.fillStyle = 'rgba(255,255,255,0.06)';
+          ctx.fillRect(0, 0, canvas.width, canvas.height);
+          ctx.restore();
+        }
+      }
+
+      document.addEventListener('keydown', (event) => {
+        const key = event.key;
+        if (key === 'ArrowUp') { event.preventDefault(); setDirection(0, -1); }
+        else if (key === 'ArrowDown') { event.preventDefault(); setDirection(0, 1); }
+        else if (key === 'ArrowLeft') { event.preventDefault(); setDirection(-1, 0); }
+        else if (key === 'ArrowRight') { event.preventDefault(); setDirection(1, 0); }
+        else if (key === 'r' || key === 'R') { restartGame(); }
+        else if (!running && !gameOver && (key === 'Enter' || key === ' ')) { startGame(); }
+      });
+
+      restartBtn.addEventListener('click', restartGame);
+
+      resetGame();
+      requestAnimationFrame(update);
+    })();
+  </script>
+</body>
+</html>
*** End Patch

